// Product of Array Except Self - O(n) time, O(1) extra space
public int[] productExceptSelf(int[] nums) {
    int n = nums.length;
    int[] result = new int[n];

    // Step 1: Build prefix products in result array
    // result[i] = product of all elements before i
    result[0] = 1;
    for (int i = 1; i < n; i++) {
        result[i] = result[i - 1] * nums[i - 1];
    }
    // result = [1, 1, 2, 6] for nums = [1, 2, 3, 4]

    // Step 2: Multiply by suffix products (computed on-the-fly)
    // suffix = product of all elements after i
    int suffix = 1;
    for (int i = n - 1; i >= 0; i--) {
        result[i] *= suffix;  // Multiply prefix by suffix
        suffix *= nums[i];    // Update suffix for next iteration
    }
    // Final: [24, 12, 8, 6]

    return result;
}

