// Kadane's Algorithm - Maximum Subarray Sum
public int maxSubArray(int[] nums) {
    int maxSum = nums[0];      // Global maximum
    int currentSum = nums[0];  // Maximum ending at current position

    for (int i = 1; i < nums.length; i++) {
        // Decision: extend previous subarray or start new?
        // If currentSum < 0, starting fresh is better
        currentSum = Math.max(nums[i], currentSum + nums[i]);

        // Update global maximum
        maxSum = Math.max(maxSum, currentSum);
    }

    return maxSum;
}

// Variant: Also track the subarray indices
public int[] maxSubArrayWithIndices(int[] nums) {
    int maxSum = nums[0], currentSum = nums[0];
    int start = 0, end = 0, tempStart = 0;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] > currentSum + nums[i]) {
            currentSum = nums[i];
            tempStart = i;  // Start new subarray
        } else {
            currentSum += nums[i];
        }

        if (currentSum > maxSum) {
            maxSum = currentSum;
            start = tempStart;
            end = i;
        }
    }

    return new int[] {maxSum, start, end};
}

