// Variant: Maximum Product Subarray
// Track both max and min (negative * negative = positive)
function maxProduct(nums) {
    let maxProd = nums[0];
    let currMax = nums[0];
    let currMin = nums[0];  // Need this for negative numbers!

    for (let i = 1; i < nums.length; i++) {
        const temp = currMax;
        currMax = Math.max(nums[i], nums[i] * currMax, nums[i] * currMin);
        currMin = Math.min(nums[i], nums[i] * temp, nums[i] * currMin);
        maxProd = Math.max(maxProd, currMax);
    }

    return maxProd;
}

