// Count Subarrays with Sum K
public int subarraySum(int[] nums, int k) {
    // Map: prefix sum -> count of occurrences
    Map<Integer, Integer> prefixCount = new HashMap<>();
    prefixCount.put(0, 1);  // Empty prefix has sum 0

    int currentSum = 0;
    int count = 0;

    for (int num : nums) {
        currentSum += num;

        // If (currentSum - k) exists as a prefix sum,
        // then subarray between that prefix and current = k
        int complement = currentSum - k;
        count += prefixCount.getOrDefault(complement, 0);

        // Add current prefix sum to map
        prefixCount.merge(currentSum, 1, Integer::sum);
    }

    return count;
}

// Longest Subarray with Sum K (for positive numbers)
public int lenOfLongSubarr(int[] nums, int k) {
    Map<Integer, Integer> firstOccurrence = new HashMap<>();
    firstOccurrence.put(0, -1);  // Empty prefix at index -1

    int currentSum = 0;
    int maxLen = 0;

    for (int i = 0; i < nums.length; i++) {
        currentSum += nums[i];

        if (firstOccurrence.containsKey(currentSum - k)) {
            int len = i - firstOccurrence.get(currentSum - k);
            maxLen = Math.max(maxLen, len);
        }

        // Only store first occurrence (for longest subarray)
        firstOccurrence.putIfAbsent(currentSum, i);
    }

    return maxLen;
}

