function findMaxLength(nums) {
    const firstOccurrence = new Map([[0, -1]]);
    let sum = 0;
    let maxLen = 0;

    for (let i = 0; i < nums.length; i++) {
        sum += nums[i] === 0 ? -1 : 1;

        if (firstOccurrence.has(sum)) {
            maxLen = Math.max(maxLen, i - firstOccurrence.get(sum));
        } else {
            firstOccurrence.set(sum, i);
        }
    }

    return maxLen;
}

