// Generic Backtracking Template
void backtrack(State current, List<Result> results) {
    // Base case: goal reached
    if (isGoal(current)) {
        results.add(copy(current));
        return;
    }

    // Try each choice
    for (Choice choice : getChoices(current)) {
        // Pruning: skip invalid choices
        if (!isValid(choice, current)) continue;

        // Make choice
        applyChoice(current, choice);

        // Recurse
        backtrack(current, results);

        // Undo choice (BACKTRACK)
        undoChoice(current, choice);
    }
}

