public List<List<String>> partition(String s) {
    List<List<String>> result = new ArrayList<>();
    backtrack(s, 0, new ArrayList<>(), result);
    return result;
}

void backtrack(String s, int start, List<String> path, List<List<String>> result) {
    // Base case: partitioned entire string
    if (start == s.length()) {
        result.add(new ArrayList<>(path));
        return;
    }

    // Try all possible first partitions
    for (int end = start; end < s.length(); end++) {
        // Only proceed if current partition is palindrome
        if (isPalindrome(s, start, end)) {
            path.add(s.substring(start, end + 1));
            backtrack(s, end + 1, path, result);
            path.remove(path.size() - 1);  // Backtrack
        }
    }
}

boolean isPalindrome(String s, int lo, int hi) {
    while (lo < hi) {
        if (s.charAt(lo++) != s.charAt(hi--)) return false;
    }
    return true;
}

