/*
 * DP THINKING FRAMEWORK - Example: Climbing Stairs
 * 
 * STEP 1: IDENTIFY THE PROBLEM TYPE
 * - Question: Count ways to reach step n (can take 1 or 2 steps)
 * - This is a COUNTING problem -> likely DP
 * 
 * STEP 2: DEFINE STATE & DECISIONS
 * - STATE: Current step number (what position am I at?)
 * - DECISION: At each step, should I take 1 step or 2 steps?
 * - CHOICES: Take 1 step OR Take 2 steps
 * 
 * STEP 3: WRITE RECURRENCE (in words first)
 * - ways(n) = ways(n-1) + ways(n-2)
 * - "Ways to reach step n = ways to reach n-1 (then take 1) + ways to reach n-2 (then take 2)"
 * 
 * STEP 4: IDENTIFY BASE CASES
 * - ways(0) = 1 (one way to stay at ground)
 * - ways(1) = 1 (one way to reach step 1)
 */

// STEP 1: PURE RECURSION (Brute Force)
// Time: O(2^n) - Exponential! Each call branches into 2
// Space: O(n) - Recursion stack depth
public int climbStairsRecursive(int n) {
    // Base cases
    if (n <= 1) return 1;

    // DECISION: Take 1 step OR Take 2 steps
    // Recursive calls for each CHOICE
    return climbStairsRecursive(n - 1) + climbStairsRecursive(n - 2);
}

// STEP 2: MEMOIZATION (Top-Down DP)
// Add a cache to avoid recomputing same subproblems
// Time: O(n) - Each state computed only once
// Space: O(n) - Cache + recursion stack
public int climbStairsMemo(int n) {
    int[] memo = new int[n + 1];
    Arrays.fill(memo, -1);
    return helper(n, memo);
}

private int helper(int n, int[] memo) {
    if (n <= 1) return 1;
    if (memo[n] != -1) return memo[n];  // Already computed!

    memo[n] = helper(n - 1, memo) + helper(n - 2, memo);
    return memo[n];
}

// STEP 3: TABULATION (Bottom-Up DP)
// Convert recursion to iteration by filling table from base cases
// Time: O(n)
// Space: O(n)
public int climbStairsTab(int n) {
    if (n <= 1) return 1;
    int[] dp = new int[n + 1];

    // Base cases
    dp[0] = 1;
    dp[1] = 1;

    // Fill table from smallest to largest (bottom-up)
    for (int i = 2; i <= n; i++) {
        dp[i] = dp[i - 1] + dp[i - 2];
    }
    return dp[n];
}

// STEP 4: SPACE OPTIMIZATION
// If dp[i] only depends on dp[i-1] and dp[i-2], use 2 variables
// Time: O(n)
// Space: O(1)
public int climbStairsOptimized(int n) {
    if (n <= 1) return 1;
    int prev2 = 1;  // dp[i-2]
    int prev1 = 1;  // dp[i-1]

    for (int i = 2; i <= n; i++) {
        int curr = prev1 + prev2;
        prev2 = prev1;
        prev1 = curr;
    }
    return prev1;
}

