/*
 * UNIVERSAL DP FRAMEWORK
 * Example: House Robber - Max money robbing non-adjacent houses
 * 
 * STEP 1: DEFINE THE PROBLEM
 * - Input: Array of house values [2, 7, 9, 3, 1]
 * - Output: Maximum money (can't rob adjacent houses)
 * 
 * STEP 2: IDENTIFY STATE & DECISION
 * - STATE: Current house index i
 * - DECISION at each house: ROB it or SKIP it
 * - CHOICES:
 *   - ROB: Take nums[i] + answer for i+2 (skip next house)
 *   - SKIP: Take answer for i+1 (move to next house)
 * 
 * STEP 3: RECURRENCE
 * - rob(i) = max(nums[i] + rob(i+2), rob(i+1))
 * - In words: max of (rob this house + best from i+2) vs (skip and best from i+1)
 * 
 * STEP 4: BASE CASES  
 * - rob(n) = 0 (no more houses)
 * - rob(n-1) = nums[n-1] (only one house left, rob it)
 */

// RECURSION (Brute Force) - O(2^n) time
public int robRecursive(int[] nums, int i) {
    if (i >= nums.length) return 0;

    int rob = nums[i] + robRecursive(nums, i + 2);   // ROB this house
    int skip = robRecursive(nums, i + 1);            // SKIP this house
    return Math.max(rob, skip);
}

// MEMOIZATION (Top-Down) - O(n) time, O(n) space
public int robMemo(int[] nums) {
    int[] memo = new int[nums.length];
    Arrays.fill(memo, -1);
    return robHelper(nums, 0, memo);
}

private int robHelper(int[] nums, int i, int[] memo) {
    if (i >= nums.length) return 0;
    if (memo[i] != -1) return memo[i];

    int rob = nums[i] + robHelper(nums, i + 2, memo);
    int skip = robHelper(nums, i + 1, memo);
    memo[i] = Math.max(rob, skip);
    return memo[i];
}

// TABULATION (Bottom-Up) - O(n) time, O(n) space
public int robTab(int[] nums) {
    int n = nums.length;
    if (n == 0) return 0;
    if (n == 1) return nums[0];

    int[] dp = new int[n];
    dp[0] = nums[0];                      // Base case: only first house
    dp[1] = Math.max(nums[0], nums[1]);   // Base case: max of first two

    for (int i = 2; i < n; i++) {
        dp[i] = Math.max(dp[i-1], nums[i] + dp[i-2]);
        //       SKIP       vs    ROB
    }
    return dp[n-1];
}

// SPACE OPTIMIZED - O(n) time, O(1) space
public int robOptimized(int[] nums) {
    int prev2 = 0;  // dp[i-2]
    int prev1 = 0;  // dp[i-1]

    for (int num : nums) {
        int curr = Math.max(prev1, num + prev2);
        prev2 = prev1;
        prev1 = curr;
    }
    return prev1;
}

