// The DP Framework Applied: Climbing Stairs
// Problem: How many ways to climb n stairs (1 or 2 steps)?

// Step 1: State = current step number
// dp[i] = number of ways to reach step i

// Step 2: Recurrence
// To reach step i, I either:
//   - Came from step i-1 (took 1 step)
//   - Came from step i-2 (took 2 steps)
// dp[i] = dp[i-1] + dp[i-2]

// Step 3: Base cases
// dp[0] = 1 (one way to stay at ground)
// dp[1] = 1 (one way to reach step 1)

// Step 4: Order - fill from 2 to n
// Step 5: Answer is dp[n]

public int climbStairs(int n) {
    if (n <= 1) return 1;

    int[] dp = new int[n + 1];
    dp[0] = 1;  // Base case
    dp[1] = 1;  // Base case

    for (int i = 2; i <= n; i++) {
        dp[i] = dp[i - 1] + dp[i - 2];  // Recurrence
    }

    return dp[n];  // Answer
}

