// STAGE 1: PURE RECURSION
// Time: O(2^n) | Space: O(n) recursion stack
public int robRecursive(int[] nums, int i) {
    // Base case: no more houses
    if (i >= nums.length) return 0;

    // CHOICE 1: Rob this house, skip next
    int rob = nums[i] + robRecursive(nums, i + 2);

    // CHOICE 2: Skip this house
    int skip = robRecursive(nums, i + 1);

    return Math.max(rob, skip);
}

// STAGE 2: MEMOIZATION
// Time: O(n) | Space: O(n) memo + stack
public int robMemo(int[] nums) {
    int[] memo = new int[nums.length];
    Arrays.fill(memo, -1);
    return robMemoHelper(nums, 0, memo);
}

private int robMemoHelper(int[] nums, int i, int[] memo) {
    if (i >= nums.length) return 0;

    // Check cache first!
    if (memo[i] != -1) return memo[i];

    int rob = nums[i] + robMemoHelper(nums, i + 2, memo);
    int skip = robMemoHelper(nums, i + 1, memo);

    // Store in cache before returning
    memo[i] = Math.max(rob, skip);
    return memo[i];
}

// STAGE 3: TABULATION
// Time: O(n) | Space: O(n) dp array only
public int robTabulation(int[] nums) {
    int n = nums.length;
    if (n == 0) return 0;
    if (n == 1) return nums[0];

    // dp[i] = max money from house i to end
    int[] dp = new int[n + 2];  // +2 for base cases

    // Fill from right to left
    for (int i = n - 1; i >= 0; i--) {
        int rob = nums[i] + dp[i + 2];
        int skip = dp[i + 1];
        dp[i] = Math.max(rob, skip);
    }

    return dp[0];
}

// STAGE 4: SPACE OPTIMIZED
// Time: O(n) | Space: O(1) - just 2 variables!
public int robOptimized(int[] nums) {
    int next1 = 0;  // dp[i+1]
    int next2 = 0;  // dp[i+2]

    for (int i = nums.length - 1; i >= 0; i--) {
        int curr = Math.max(nums[i] + next2, next1);
        next2 = next1;
        next1 = curr;
    }

    return next1;
}

