// MEMOIZATION (Top-Down)
// Start with recursive solution, add cache
public int fibMemo(int n) {
    int[] memo = new int[n + 1];
    Arrays.fill(memo, -1);
    return helper(n, memo);
}

private int helper(int n, int[] memo) {
    // Base cases
    if (n <= 1) return n;

    // Check cache
    if (memo[n] != -1) return memo[n];

    // Compute and cache
    memo[n] = helper(n - 1, memo) + helper(n - 2, memo);
    return memo[n];
}

// TABULATION (Bottom-Up)
// Build table from base cases
public int fibTab(int n) {
    if (n <= 1) return n;

    int[] dp = new int[n + 1];
    dp[0] = 0;
    dp[1] = 1;

    for (int i = 2; i <= n; i++) {
        dp[i] = dp[i - 1] + dp[i - 2];
    }

    return dp[n];
}

// SPACE OPTIMIZED
// Only need last 2 values
public int fibOptimized(int n) {
    if (n <= 1) return n;

    int prev2 = 0, prev1 = 1;

    for (int i = 2; i <= n; i++) {
        int curr = prev1 + prev2;
        prev2 = prev1;
        prev1 = curr;
    }

    return prev1;
}

