// 0/1 Knapsack
public int knapsack(int[] weights, int[] values, int capacity) {
    int n = weights.length;
    int[][] dp = new int[n + 1][capacity + 1];

    for (int i = 1; i <= n; i++) {
        for (int w = 0; w <= capacity; w++) {
            // Skip item
            dp[i][w] = dp[i - 1][w];

            // Take item (if possible)
            if (weights[i - 1] <= w) {
                dp[i][w] = Math.max(
                    dp[i][w],
                    dp[i - 1][w - weights[i - 1]] + values[i - 1]
                );
            }
        }
    }

    return dp[n][capacity];
}

// Partition Equal Subset Sum
// Can we split array into two subsets with equal sum?
public boolean canPartition(int[] nums) {
    int sum = Arrays.stream(nums).sum();
    if (sum % 2 != 0) return false;

    int target = sum / 2;
    boolean[] dp = new boolean[target + 1];
    dp[0] = true;

    for (int num : nums) {
        // Iterate backwards to avoid using same element twice
        for (int j = target; j >= num; j--) {
            dp[j] = dp[j] || dp[j - num];
        }
    }

    return dp[target];
}

// Target Sum - Count ways to reach target with +/-
public int findTargetSumWays(int[] nums, int target) {
    int sum = Arrays.stream(nums).sum();
    // We need: positives - negatives = target
    // positives + negatives = sum
    // So: positives = (sum + target) / 2
    if ((sum + target) % 2 != 0 || sum < Math.abs(target)) return 0;

    int newTarget = (sum + target) / 2;
    int[] dp = new int[newTarget + 1];
    dp[0] = 1;

    for (int num : nums) {
        for (int j = newTarget; j >= num; j--) {
            dp[j] += dp[j - num];
        }
    }

    return dp[newTarget];
}

