// Task Scheduler
public int leastInterval(char[] tasks, int n) {
    int[] freq = new int[26];
    for (char c : tasks) freq[c - 'A']++;

    int maxFreq = 0, maxCount = 0;
    for (int f : freq) {
        if (f > maxFreq) { maxFreq = f; maxCount = 1; }
        else if (f == maxFreq) maxCount++;
    }

    // (maxFreq - 1) full cycles + final partial cycle
    int result = (maxFreq - 1) * (n + 1) + maxCount;
    return Math.max(result, tasks.length);
}

// Reorganize String - no adjacent same chars
public String reorganizeString(String s) {
    int[] freq = new int[26];
    for (char c : s.toCharArray()) freq[c - 'a']++;

    PriorityQueue<int[]> heap = new PriorityQueue<>((a, b) -> b[0] - a[0]);
    for (int i = 0; i < 26; i++) {
        if (freq[i] > 0) heap.offer(new int[]{freq[i], i});
    }

    StringBuilder sb = new StringBuilder();
    int[] prev = null;

    while (!heap.isEmpty()) {
        int[] curr = heap.poll();
        sb.append((char)(curr[1] + 'a'));
        curr[0]--;

        if (prev != null && prev[0] > 0) heap.offer(prev);
        prev = curr;
    }

    return sb.length() == s.length() ? sb.toString() : "";
}

