        // Update minimum (best buy price so far)
        minPrice = Math.min(minPrice, price);

        // Calculate profit if we sell today
        int profit = price - minPrice;

        // Update max profit
        maxProfit = Math.max(maxProfit, profit);
    }

    return maxProfit;
}

