public int numRescueBoats(int[] people, int limit) {
    Arrays.sort(people);
    int left = 0;
    int right = people.length - 1;
    int boats = 0;

    while (left <= right) {
        // Heaviest person always takes a boat
        boats++;

        // Can lightest person join?
        if (people[left] + people[right] <= limit) {
            left++;  // Lightest joins
        }

        right--;  // Heaviest always goes
    }

    return boats;
}

