public Node cloneGraph(Node node) {
    if (node == null) return null;

    Map<Node, Node> cloned = new HashMap<>();
    return clone(node, cloned);
}

private Node clone(Node node, Map<Node, Node> cloned) {
    // Already cloned? Return it
    if (cloned.containsKey(node)) {
        return cloned.get(node);
    }

    // Create clone and store BEFORE recursing (handles cycles)
    Node copy = new Node(node.val, new ArrayList<>());
    cloned.put(node, copy);

    // Clone all neighbors
    for (Node neighbor : node.neighbors) {
        copy.neighbors.add(clone(neighbor, cloned));
    }

    return copy;
}

