    const cloned = new Map();

    function clone(n) {
        if (cloned.has(n)) {
            return cloned.get(n);
        }

        const copy = { val: n.val, neighbors: [] };
        cloned.set(n, copy);

        for (const neighbor of n.neighbors) {
            copy.neighbors.push(clone(neighbor));
        }

        return copy;
    }

    return clone(node);
}

