            if (color[neighbor] === 0 && dfs(neighbor)) return true;
        }

        color[node] = 2;  // Black
        return false;
    }

    for (let i = 0; i < n; i++) {
        if (color[i] === 0 && dfs(i)) return true;
    }
    return false;
}

