function minCostConnectPoints(points) {
    const n = points.length;
    const edges = [];

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const cost = Math.abs(points[i][0] - points[j][0]) +
                         Math.abs(points[i][1] - points[j][1]);
            edges.push([cost, i, j]);
        }
    }

    edges.sort((a, b) => a[0] - b[0]);

    const parent = Array.from({length: n}, (_, i) => i);

    function find(x) {
        if (parent[x] !== x) parent[x] = find(parent[x]);
        return parent[x];
    }

    let totalCost = 0, edgesUsed = 0;

    for (const [cost, u, v] of edges) {
        const pu = find(u), pv = find(v);
        if (pu !== pv) {
            parent[pu] = pv;
            totalCost += cost;
            if (++edgesUsed === n - 1) break;
        }
    }

    return totalCost;
}

tutorial.content:
**DFS Template:**
```
function dfs(node, visited):
    visited.add(node)
    // Process node
    for neighbor in graph[node]:
        if neighbor not in visited:
            dfs(neighbor, visited)
```

**BFS Template:**
```
function bfs(start):
    queue = [start]
    visited = {start}
    level = 0

    while queue not empty:
        size = queue.length
        for i in 0..size:
            node = queue.dequeue()
            // Process node
            for neighbor in graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)  // Mark BEFORE adding
                    queue.enqueue(neighbor)
        level++
```

**Topological Sort (Kahn's):**
```
function topoSort(n, edges):
    build graph and indegree array
    queue = all nodes with indegree 0
    order = []

    while queue not empty:
        node = queue.dequeue()
        order.append(node)
        for neighbor in graph[node]:
            indegree[neighbor]--
            if indegree[neighbor] == 0:
                queue.enqueue(neighbor)

    return order if len(order) == n else []  // [] = cycle
```

**Dijkstra:**
```
function dijkstra(graph, start):
    dist = [Infinity] × n
    dist[start] = 0
    pq = MinHeap([(0, start)])

    while pq not empty:
        d, u = pq.pop()
        if d > dist[u]: continue  // Skip stale

        for (v, w) in graph[u]:
            if dist[u] + w < dist[v]:
                dist[v] = dist[u] + w
                pq.push((dist[v], v))

    return dist
```

**Interview Tips:**
- Always clarify: directed vs undirected?
- Draw the graph when debugging
- Check for disconnected components
- Remember: BFS = shortest path (unweighted)

