public boolean isValidSudoku(char[][] board) {
    Set<String> seen = new HashSet<>();

    for (int i = 0; i < 9; i++) {
        for (int j = 0; j < 9; j++) {
            char num = board[i][j];
            if (num == '.') continue;

            int boxIndex = (i / 3) * 3 + (j / 3);

            // Create unique keys for row, col, and box
            String rowKey = "row" + i + num;
            String colKey = "col" + j + num;
            String boxKey = "box" + boxIndex + num;

            // If any key already exists, invalid
            if (!seen.add(rowKey) || 
                !seen.add(colKey) || 
                !seen.add(boxKey)) {
                return false;
            }
        }
    }

    return true;
}

