            if (num === '.') continue;

            const boxIndex = Math.floor(i / 3) * 3 + Math.floor(j / 3);

            const rowKey = `row${i}:${num}`;
            const colKey = `col${j}:${num}`;
            const boxKey = `box${boxIndex}:${num}`;

            if (seen.has(rowKey) || seen.has(colKey) || seen.has(boxKey)) {
                return false;
            }

            seen.add(rowKey);
            seen.add(colKey);
            seen.add(boxKey);
