        sum += num;

        // How many prefixes have sum = (sum - k)?
        count += prefixCount.get(sum - k) || 0;

        // Record current prefix sum
        prefixCount.set(sum, (prefixCount.get(sum) || 0) + 1);
    }

    return count;
}

