// Meeting Rooms II - Track ongoing meetings with min-heap
public int minMeetingRooms(int[][] intervals) {
    if (intervals.length == 0) return 0;

    Arrays.sort(intervals, (a, b) -> a[0] - b[0]);  // Sort by start
    PriorityQueue<Integer> endTimes = new PriorityQueue<>();  // Min-heap of end times

    endTimes.offer(intervals[0][1]);

    for (int i = 1; i < intervals.length; i++) {
        // If earliest ending meeting ends before this one starts
        if (intervals[i][0] >= endTimes.peek()) {
            endTimes.poll();  // Reuse the room
        }
        endTimes.offer(intervals[i][1]);  // Add this meeting's end time
    }

    return endTimes.size();  // Number of rooms = number of overlapping meetings
}

// Minimum Cost to Hire K Workers
public double mincostToHireWorkers(int[] quality, int[] wage, int k) {
    int n = quality.length;
    double[][] workers = new double[n][2];  // [ratio, quality]

    for (int i = 0; i < n; i++) {
        workers[i] = new double[]{(double) wage[i] / quality[i], quality[i]};
    }

    Arrays.sort(workers, (a, b) -> Double.compare(a[0], b[0]));

    PriorityQueue<Double> maxHeap = new PriorityQueue<>(Collections.reverseOrder());
    double sumQuality = 0, minCost = Double.MAX_VALUE;

    for (double[] worker : workers) {
        sumQuality += worker[1];
        maxHeap.offer(worker[1]);

        if (maxHeap.size() > k) {
            sumQuality -= maxHeap.poll();  // Remove highest quality
        }

        if (maxHeap.size() == k) {
            minCost = Math.min(minCost, sumQuality * worker[0]);
        }
    }
    return minCost;
}

