public int leastInterval(char[] tasks, int n) {
    // Count frequencies
    int[] freq = new int[26];
    for (char task : tasks) {
        freq[task - 'A']++;
    }

    // Max-heap of frequencies
    PriorityQueue<Integer> heap = new PriorityQueue<>(Collections.reverseOrder());
    for (int f : freq) {
        if (f > 0) heap.offer(f);
    }

    int time = 0;

    while (!heap.isEmpty()) {
        List<Integer> temp = new ArrayList<>();
        int cycle = n + 1;  // Each cycle is n+1 time units

        // Execute up to n+1 different tasks
        while (cycle > 0 && !heap.isEmpty()) {
            int count = heap.poll();
            if (count > 1) {
                temp.add(count - 1);
            }
            time++;
            cycle--;
        }

        // Put remaining tasks back
        heap.addAll(temp);

        // If tasks remain, add idle time
        if (!heap.isEmpty()) {
            time += cycle;
        }
    }

    return time;
}

// Formula approach - O(n)
public int leastIntervalFormula(char[] tasks, int n) {
    int[] freq = new int[26];
    for (char task : tasks) freq[task - 'A']++;

    int maxFreq = 0, maxCount = 0;
    for (int f : freq) {
        if (f > maxFreq) {
            maxFreq = f;
            maxCount = 1;
        } else if (f == maxFreq) {
            maxCount++;
        }
    }

    return Math.max(tasks.length, (maxFreq - 1) * (n + 1) + maxCount);
}

