public String reorganizeString(String s) {
    int[] freq = new int[26];
    for (char c : s.toCharArray()) freq[c - 'a']++;

    // Check if possible
    int maxFreq = 0;
    for (int f : freq) maxFreq = Math.max(maxFreq, f);
    if (maxFreq > (s.length() + 1) / 2) return "";

    // Max-heap: [freq, char]
    PriorityQueue<int[]> heap = new PriorityQueue<>((a, b) -> b[0] - a[0]);
    for (int i = 0; i < 26; i++) {
        if (freq[i] > 0) heap.offer(new int[]{freq[i], i});
    }

    StringBuilder sb = new StringBuilder();
    int[] prev = null;

    while (!heap.isEmpty()) {
        int[] curr = heap.poll();
        sb.append((char)(curr[1] + 'a'));
        curr[0]--;

        // Add back previous if it still has count
        if (prev != null && prev[0] > 0) {
            heap.offer(prev);
        }
        prev = curr;
    }

    return sb.toString();
}

