function medianSlidingWindow(nums, k) {
    // Simplified: use sorted arrays (interview clarity)
    const window = [];
    const result = [];

    for (let i = 0; i < nums.length; i++) {
        // Insert maintaining sorted order
        const idx = binarySearchInsert(window, nums[i]);
        window.splice(idx, 0, nums[i]);

        // Remove old element when window is full
        if (i >= k) {
            const removeIdx = binarySearchInsert(window, nums[i - k]);
            window.splice(removeIdx, 1);
        }

        // Record median
        if (i >= k - 1) {
            const mid = Math.floor(k / 2);
            if (k % 2 === 1) {
                result.push(window[mid]);
            } else {
                result.push((window[mid - 1] + window[mid]) / 2);
            }
        }
    }
    return result;
}

function binarySearchInsert(arr, target) {
    let lo = 0, hi = arr.length;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (arr[mid] < target) lo = mid + 1;
        else hi = mid;
    }
    return lo;
}

