public ListNode reverseBetween(ListNode head, int left, int right) {
    if (head == null || left == right) return head;

    ListNode dummy = new ListNode(0);
    dummy.next = head;
    ListNode prev = dummy;

    // Move prev to node before 'left' position
    for (int i = 1; i < left; i++) {
        prev = prev.next;
    }

    // curr is at 'left' position - will be tail after reverse
    ListNode curr = prev.next;

    // Reverse from left to right using insertion
    for (int i = 0; i < right - left; i++) {
        ListNode next = curr.next;    // Node to move
        curr.next = next.next;        // Skip over it
        next.next = prev.next;        // Insert at front
        prev.next = next;             // Update prev's next
    }

    return dummy.next;
}

