public ListNode mergeTwoLists(ListNode l1, ListNode l2) {
    ListNode dummy = new ListNode(0);
    ListNode tail = dummy;  // Build result from here

    while (l1 != null && l2 != null) {
        if (l1.val <= l2.val) {
            tail.next = l1;   // Take from l1
            l1 = l1.next;     // Advance l1
        } else {
            tail.next = l2;   // Take from l2
            l2 = l2.next;     // Advance l2
        }
        tail = tail.next;     // Advance tail
    }

    // Append remaining (one list might have leftovers)
    tail.next = (l1 != null) ? l1 : l2;

    return dummy.next;
}

