public ListNode oddEvenList(ListNode head) {
    if (head == null || head.next == null) return head;

    ListNode odd = head;           // First odd node
    ListNode even = head.next;     // First even node
    ListNode evenHead = even;      // Save to connect later

    while (even != null && even.next != null) {
        odd.next = even.next;      // Skip even, link to next odd
        odd = odd.next;            // Move odd pointer

        even.next = odd.next;      // Skip odd, link to next even
        even = even.next;          // Move even pointer
    }

    odd.next = evenHead;           // Connect odd list to even list

    return head;
}

