public ListNode reverseKGroup(ListNode head, int k) {
    ListNode dummy = new ListNode(0);
    dummy.next = head;
    ListNode groupPrev = dummy;

    while (true) {
        // Check if k nodes exist
        ListNode kth = getKth(groupPrev, k);
        if (kth == null) break;  // Less than k nodes remain

        ListNode groupNext = kth.next;  // Save node after group

        // Reverse k nodes
        ListNode prev = groupNext;  // Will be new end
        ListNode curr = groupPrev.next;
        while (curr != groupNext) {
            ListNode next = curr.next;
            curr.next = prev;
            prev = curr;
            curr = next;
        }

        // Connect: groupPrev -> kth (new first)
        // Original first (groupPrev.next) is now last
        ListNode tmp = groupPrev.next;  // Save original first
        groupPrev.next = kth;           // Point to new first
        groupPrev = tmp;                // Move to new last (for next group)
    }

    return dummy.next;
}

private ListNode getKth(ListNode node, int k) {
    while (node != null && k > 0) {
        node = node.next;
        k--;
    }
    return node;  // Returns kth node or null if < k nodes
}

