// Solution 1: HashMap approach (clearer)
public Node copyRandomList(Node head) {
    if (head == null) return null;

    // Map original -> copy
    Map<Node, Node> map = new HashMap<>();

    // First pass: create all nodes
    Node curr = head;
    while (curr != null) {
        map.put(curr, new Node(curr.val));
        curr = curr.next;
    }

    // Second pass: set next and random pointers
    curr = head;
    while (curr != null) {
        Node copy = map.get(curr);
        copy.next = map.get(curr.next);
        copy.random = map.get(curr.random);
        curr = curr.next;
    }

    return map.get(head);
}

// Solution 2: O(1) space - Interweaving
public Node copyRandomListOptimal(Node head) {
    if (head == null) return null;

    // Step 1: Interweave - insert copies after originals
    Node curr = head;
    while (curr != null) {
        Node copy = new Node(curr.val);
        copy.next = curr.next;
        curr.next = copy;
        curr = copy.next;
    }

    // Step 2: Set random pointers for copies
    curr = head;
    while (curr != null) {
        if (curr.random != null) {
            curr.next.random = curr.random.next;
        }
        curr = curr.next.next;
    }

    // Step 3: Separate the two lists
    Node dummy = new Node(0);
    Node copyTail = dummy;
    curr = head;
    while (curr != null) {
        copyTail.next = curr.next;  // Add copy to result
        copyTail = copyTail.next;
        curr.next = curr.next.next; // Restore original
        curr = curr.next;
    }

    return dummy.next;
}

