        result[i] = result[i - 1] * nums[i - 1];
    }

    // Pass 2: Multiply by product of all elements RIGHT of i
    let rightProduct = 1;
    for (let i = n - 1; i >= 0; i--) {
        result[i] *= rightProduct;
        rightProduct *= nums[i];
    }

    return result;
}

