public boolean checkSubarraySum(int[] nums, int k) {
    Map<Integer, Integer> remainderIndex = new HashMap<>();
    remainderIndex.put(0, -1);  // Remainder 0 seen at index -1

    int sum = 0;

    for (int i = 0; i < nums.length; i++) {
        sum += nums[i];

        int remainder = k == 0 ? sum : sum % k;

        if (remainderIndex.containsKey(remainder)) {
            // Check if subarray length >= 2
            if (i - remainderIndex.get(remainder) >= 2) {
                return true;
            }
        } else {
            // Only store FIRST occurrence
            remainderIndex.put(remainder, i);
        }
    }

    return false;
}

