public int pathSum(TreeNode root, int targetSum) {
    Map<Long, Integer> prefixCount = new HashMap<>();
    prefixCount.put(0L, 1);  // Empty path
    return dfs(root, 0, targetSum, prefixCount);
}

private int dfs(TreeNode node, long currentSum, int target,
                Map<Long, Integer> prefixCount) {
    if (node == null) return 0;

    currentSum += node.val;

    // Count paths ending at current node
    int count = prefixCount.getOrDefault(currentSum - target, 0);

    // Add current prefix sum
    prefixCount.merge(currentSum, 1, Integer::sum);

    // Recurse
    count += dfs(node.left, currentSum, target, prefixCount);
    count += dfs(node.right, currentSum, target, prefixCount);

    // BACKTRACK: Remove current sum before returning
    prefixCount.merge(currentSum, -1, Integer::sum);

    return count;
}

