        // Pop all elements smaller than current
        // Current element is their "next greater"
        while (stack.length > 0 && 
               nums[stack[stack.length - 1]] < nums[i]) {
            const idx = stack.pop();
            result[idx] = nums[i];
        }
        stack.push(i);
    }

    // Elements still in stack have no next greater
    // (already initialized to -1)
    return result;
}

