function largestRectangleArea(heights) {
    const stack = [];  // Increasing stack of indices
    let maxArea = 0;

    // Process all bars + sentinel (height 0)
    for (let i = 0; i <= heights.length; i++) {
        const h = i === heights.length ? 0 : heights[i];

        // Pop taller bars - they can't extend further right
        while (stack.length > 0 && 
               heights[stack[stack.length - 1]] > h) {
            const height = heights[stack.pop()];

            // Width: from stack top to current position
            const width = stack.length === 0 
                ? i 
                : i - stack[stack.length - 1] - 1;

            maxArea = Math.max(maxArea, height * width);
        }
        stack.push(i);
    }

    return maxArea;
}

