function calculate(s) {
    const stack = [];
    let num = 0;
    let prevOp = '+';  // Start with '+'

    for (let i = 0; i <= s.length; i++) {
        const c = i < s.length ? s[i] : '+';  // Sentinel

        if (c >= '0' && c <= '9') {
            num = num * 10 + Number(c);
        } else if (c !== ' ') {
            // Apply previous operator
            if (prevOp === '+') {
                stack.push(num);
            } else if (prevOp === '-') {
                stack.push(-num);
            } else if (prevOp === '*') {
                stack.push(stack.pop() * num);
            } else if (prevOp === '/') {
                // Integer division toward zero
                stack.push(Math.trunc(stack.pop() / num));
            }

            prevOp = c;
            num = 0;
        }
    }

    return stack.reduce((a, b) => a + b, 0);
}

