// Kth Smallest in BST
public int kthSmallest(TreeNode root, int k) {
    int[] state = {0, 0};  // [count, result]
    inorder(root, k, state);
    return state[1];
}

private void inorder(TreeNode node, int k, int[] state) {
    if (node == null || state[0] >= k) return;

    inorder(node.left, k, state);    // Left first

    state[0]++;                       // Count this node
    if (state[0] == k) {
        state[1] = node.val;          // Found kth!
        return;
    }

    inorder(node.right, k, state);   // Then right
}

