function deserialize(data) {
    const values = data.split(',');
    let index = 0;

    function build() {
        if (values[index] === 'null') {
            index++;
            return null;
        }

        const node = { val: parseInt(values[index]), left: null, right: null };
        index++;
        node.left = build();
        node.right = build();
        return node;
    }

    return build();
}

