public List<List<String>> suggestedProducts(String[] products, String searchWord) {
    // Build Trie
    TrieNode root = new TrieNode();
    for (String product : products) {
        TrieNode node = root;
        for (char c : product.toCharArray()) {
            int i = c - 'a';
            if (node.children[i] == null) {
                node.children[i] = new TrieNode();
            }
            node = node.children[i];
        }
        node.word = product;  // Store word at end
    }

    List<List<String>> results = new ArrayList<>();
    TrieNode node = root;

    for (char c : searchWord.toCharArray()) {
        List<String> suggestions = new ArrayList<>();

        if (node != null) {
            node = node.children[c - 'a'];
        }

        if (node != null) {
            dfs(node, suggestions);
        }

        results.add(suggestions);
    }

    return results;
}

private void dfs(TrieNode node, List<String> suggestions) {
    if (suggestions.size() == 3) return;  // Only need top 3

    if (node.word != null) {
        suggestions.add(node.word);
    }

    for (int i = 0; i < 26 && suggestions.size() < 3; i++) {
        if (node.children[i] != null) {
            dfs(node.children[i], suggestions);
        }
    }
}

