            node = node[c];
        }
        node.isEnd = true;
    }

    search(word) {
        return this._search(word, 0, this.root);
    }

    _search(word, index, node) {
        if (!node) return false;
        if (index === word.length) return node.isEnd === true;

        const c = word[index];

        if (c === '.') {
            // Try all children
            for (const key of Object.keys(node)) {
                if (key !== 'isEnd' && 
                    this._search(word, index + 1, node[key])) {
                    return true;
                }
            }
            return false;
        } else {
            return this._search(word, index + 1, node[c]);
        }
    }
}

