public String replaceWords(List<String> dictionary, String sentence) {
    // Build Trie from roots
    TrieNode root = new TrieNode();
    for (String word : dictionary) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            int i = c - 'a';
            if (node.children[i] == null) {
                node.children[i] = new TrieNode();
            }
            node = node.children[i];
        }
        node.word = word;
    }

    // Replace each word
    StringBuilder result = new StringBuilder();
    for (String word : sentence.split(" ")) {
        if (result.length() > 0) result.append(" ");
        result.append(findRoot(root, word));
    }
    return result.toString();
}

private String findRoot(TrieNode root, String word) {
    TrieNode node = root;

    for (char c : word.toCharArray()) {
        int i = c - 'a';

        // Found a root - return it immediately!
        if (node.word != null) {
            return node.word;
        }

        // Path doesn't exist - no root found
        if (node.children[i] == null) {
            return word;
        }

        node = node.children[i];
    }

    // Check if word itself is a root
    return node.word != null ? node.word : word;
}

