    return sentence.split(' ').map(word => {
        let node = root;

        for (const c of word) {
            // Found a root!
            if (node.word) return node.word;
            // Path doesn't exist
            if (!node[c]) return word;
            node = node[c];
        }

        return node.word || word;
    }).join(' ');
}

