public void sortColors(int[] nums) {
    int low = 0;   // Boundary for 0s
    int mid = 0;   // Current element
    int high = nums.length - 1;  // Boundary for 2s

    while (mid <= high) {
        if (nums[mid] == 0) {
            // Swap to low region, advance both
            swap(nums, low, mid);
            low++;
            mid++;
        } else if (nums[mid] == 1) {
            // Already in middle, just advance
            mid++;
        } else {
            // Swap to high region, only decrement high
            swap(nums, mid, high);
            high--;
            // DON'T increment mid - need to check swapped value
        }
    }
}

private void swap(int[] nums, int i, int j) {
    int temp = nums[i];
    nums[i] = nums[j];
    nums[j] = temp;
}

