function accountsMerge(accounts) {
    const emailToIndex = new Map();
    const emailToName = new Map();
    let index = 0;

    // Assign index to each unique email
    for (const account of accounts) {
        const name = account[0];
        for (let i = 1; i < account.length; i++) {
            const email = account[i];
            if (!emailToIndex.has(email)) {
                emailToIndex.set(email, index++);
            }
            emailToName.set(email, name);
        }
    }

    // Union emails in same account
    const uf = new UnionFind(index);
    for (const account of accounts) {
        const firstIdx = emailToIndex.get(account[1]);
        for (let i = 2; i < account.length; i++) {
            uf.union(firstIdx, emailToIndex.get(account[i]));
        }
    }

    // Group emails by root
    const rootToEmails = new Map();
    for (const [email, idx] of emailToIndex) {
        const root = uf.find(idx);
        if (!rootToEmails.has(root)) {
            rootToEmails.set(root, []);
        }
        rootToEmails.get(root).push(email);
    }

    // Build result
    const result = [];
    for (const [root, emails] of rootToEmails) {
        emails.sort();
        const name = emailToName.get(emails[0]);
        result.push([name, ...emails]);
    }

    return result;
}

