function largestIsland(grid) {
    const n = grid.length;
    const uf = new UnionFindWithSize(n * n);
    const dirs = [[0,1],[1,0],[0,-1],[-1,0]];

    // Build islands using Union-Find
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                const idx = i * n + j;
                for (const [di, dj] of dirs) {
                    const ni = i + di, nj = j + dj;
                    if (ni >= 0 && ni < n && nj >= 0 && nj < n && grid[ni][nj] === 1) {
                        uf.union(idx, ni * n + nj);
                    }
                }
            }
        }
    }

    let maxSize = uf.maxSize;

    // Try flipping each 0
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 0) {
                const seen = new Set(); // Avoid counting same island twice
                let size = 1; // The flipped cell itself

                for (const [di, dj] of dirs) {
                    const ni = i + di, nj = j + dj;
                    if (ni >= 0 && ni < n && nj >= 0 && nj < n && grid[ni][nj] === 1) {
                        const root = uf.find(ni * n + nj);
                        if (!seen.has(root)) {
