    edges.sort((a, b) -> a[2] - b[2]);

    UnionFind uf = new UnionFind(n);
    int totalWeight = 0;
    int edgesUsed = 0;

    for (int[] edge : edges) {
        if (uf.find(edge[0]) != uf.find(edge[1])) {
            uf.union(edge[0], edge[1]);
            totalWeight += edge[2];
            edgesUsed++;
            if (edgesUsed == n - 1) break;
        }
    }

    return totalWeight;
}

