function removeStones(stones) {
    const uf = new UnionFind(20003); // rows 0-10000, cols 10001-20002
    const seen = new Set();

    for (const [row, col] of stones) {
        // Union row with column (offset column to avoid collision)
        uf.union(row, col + 10001);
        seen.add(row);
        seen.add(col + 10001);
    }

    // Count unique components
    const roots = new Set();
