// Alternative: Use Map for arbitrary coordinates
function removeStones(stones) {
    const parent = new Map();

    function find(x) {
        if (!parent.has(x)) parent.set(x, x);
        if (parent.get(x) !== x) {
            parent.set(x, find(parent.get(x)));
        }
        return parent.get(x);
    }

    function union(x, y) {
        parent.set(find(x), find(y));
    }

    for (const [r, c] of stones) {
        union(r, ~c); // ~c gives unique negative value for columns
    }

    const roots = new Set();
    for (const [r, c] of stones) {
        roots.add(find(r));
    }

    return stones.length - roots.size;
}

